content:
{
  "sentences": [
    {
      "text": "那個人是誰？",
      "pinyin": "Nà ge rén shì shuí?",
      "pinyin_numeric": "na4 ge0 ren2 shi4 shui2",
      "translation_en": "Who is that person?",
      "translation_ko": "저 사람은 누구예요?"
    },
    {
      "text": "那個人是我朋友，他長得很高。",
      "pinyin": "Nà ge rén shì wǒ péngyǒu, tā zhǎng de hěn gāo.",
      "pinyin_numeric": "na4 ge0 ren2 shi4 wo3 peng2you3 ta1 zhang3 de0 hen3 gao1",
      "translation_en": "That person is my friend; he is very tall.",
      "translation_ko": "저 사람은 제 친구예요. 키가 아주 커요."
    },
    {
      "text": "那個人看起來很年輕，可是已經三十歲了。",
      "pinyin": "Nà ge rén kàn qǐlái hěn niánqīng, kěshì yǐjīng sān shí suì le.",
      "pinyin_numeric": "na4 ge0 ren2 kan4 qi3lai2 hen3 nian2qing1 ke3shi4 yi3jing1 san1 shi2 sui4 le0",
      "translation_en": "That person looks very young, but is already thirty years old.",
      "translation_ko": "저 사람은 아주 젊어 보이는데 벌써 서른 살이에요."
    },
    {
      "text": "那個人穿著黑色衣服，戴眼鏡，很帥。",
      "pinyin": "Nà ge rén chuān zhe hēisè yīfú, dài yǎnjìng, hěn shuài.",
      "pinyin_numeric": "na4 ge0 ren2 chuan1 zhe0 hei1se4 yi1fu2 dai4 yan3jing4 hen3 shuai4",
      "translation_en": "That person is wearing black clothes and glasses; he is very handsome.",
      "translation_ko": "저 사람은 검은 옷을 입고 안경을 썼어요. 아주 잘생겼어요."
    },
    {
      "text": "那個人是我妹妹，她個性很活潑，喜歡說話。",
      "pinyin": "Nà ge rén shì wǒ mèimei, tā gèxìng hěn huópō, xǐhuān shuōhuà.",
      "pinyin_numeric": "na4 ge0 ren2 shi4 wo3 mei4mei0 ta1 ge4xing4 hen3 huo2po1 xi3huan1 shuo1hua4",
      "translation_en": "That person is my younger sister; she has a very lively personality and likes to talk.",
      "translation_ko": "저 사람은 제 여동생이에요. 성격이 아주 활발하고 말하기 좋아해요."
    },
    {
      "text": "那個人長得很可愛，而且很友善。",
      "pinyin": "Nà ge rén zhǎng de hěn kě'ài, érqiě hěn yǒushàn.",
      "pinyin_numeric": "na4 ge0 ren2 zhang3 de0 hen3 ke3ai4 er2qie3 hen3 you3shan4",
      "translation_en": "That person looks very cute and is also very friendly.",
      "translation_ko": "저 사람은 아주 귀엽게 생겼고 친절해요."
    },
    {
      "text": "那個人是老師嗎？他看起來很認真。",
      "pinyin": "Nà ge rén shì lǎoshī ma? Tā kàn qǐlái hěn rènzhēn.",
      "pinyin_numeric": "na4 ge0 ren2 shi4 lao3shi1 ma0 ta1 kan4 qi3lai2 hen3 ren4zhen1",
      "translation_en": "Is that person a teacher? He looks very serious.",
      "translation_ko": "저 사람은 선생님인가요? 아주 진지해 보여요."
    },
    {
      "text": "那個人是我哥哥，他頭髮很短，眼睛很大。",
      "pinyin": "Nà ge rén shì wǒ gēge, tā tóufǎ hěn duǎn, yǎnjīng hěn dà.",
      "pinyin_numeric": "na4 ge0 ren2 shi4 wo3 ge1ge0 ta1 tou2fa3 hen3 duan3 yan3jing1 hen3 da4",
      "translation_en": "That person is my older brother; he has short hair and big eyes.",
      "translation_ko": "저 사람은 제 오빠예요. 머리가 짧고 눈이 커요."
    },
    {
      "text": "那個人聽說很聰明，而且個性很溫柔。",
      "pinyin": "Nà ge rén tīngshuō hěn cōngmíng, érqiě gèxìng hěn wēnróu.",
      "pinyin_numeric": "na4 ge0 ren2 ting1shuo1 hen3 cong1ming2 er2qie3 ge4xing4 hen3 wen1rou2",
      "translation_en": "I heard that person is very smart and has a gentle personality.",
      "translation_ko": "저 사람은 똑똑하고 성격도 부드럽다고 들었어요."
    },
    {
      "text": "那個人是我朋友，他喜歡穿白色衣服，看起來很乾淨。",
      "pinyin": "Nà ge rén shì wǒ péngyǒu, tā xǐhuān chuān báisè yīfú, kàn qǐlái hěn gānjìng.",
      "pinyin_numeric": "na4 ge0 ren2 shi4 wo3 peng2you3 ta1 xi3huan1 chuan1 bai2se4 yi1fu2 kan4 qi3lai2 hen3 gan1jing4",
      "translation_en": "That person is my friend; he likes to wear white clothes and looks very clean.",
      "translation_ko": "저 사람은 제 친구예요. 흰 옷 입는 걸 좋아하고 아주 깔끔해 보여요."
    }
  ]
}
